import pyotp
import qrcode
import time

class TOTPAuthenticator:
    def __init__(self):
        self.users = {}

    def generate_secret(self):
        return pyotp.random_base32()

    def create_user(self, username):
        secret = self.generate_secret()
        self.users[username] = {'secret': secret}
        return secret

    def generate_qr_code(self, username):
        secret = self.users[username]['secret']
        uri = f"otpauth://totp/{username}?secret={secret}&issuer=MyMFA"
        qr = qrcode.make(uri)
        qr.save(f"{username}_qr.png")

    def validate_totp(self, username, user_input):
        secret = self.users[username]['secret']
        totp = pyotp.TOTP(secret)
        return totp.verify(user_input)

